<?php
namespace App\Domain\Hunts\Rewards;use App\Domain\Combat\CombatResultStatus;use App\Domain\Hunts\HuntEnemyStatus;use App\Domain\Hunts\Rewards\Data\HuntRewardItemResult;use App\Domain\Hunts\Rewards\Data\HuntRewardResult;use App\Domain\Hunts\Rewards\Exceptions\InconsistentHuntRewardException;use App\Domain\Loot\LootGenerator;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Hunt;use App\Models\HuntEnemy;use App\Models\HuntReward;use App\Models\HuntRewardItem;use App\Models\Monster;use App\Models\MonsterLootEntry;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class HuntRewardService{private $loot;public function __construct(LootGenerator $loot){$this->loot=$loot;}public function generatePendingForLockedHunt($huntId,$sessionId):HuntRewardResult{if(DB::transactionLevel()<1)throw new \RuntimeException('Active transaction required.');$hunt=Hunt::whereKey($huntId)->lockForUpdate()->firstOrFail();if((int)$hunt->hunting_session_id!==(int)$sessionId||$hunt->status!==CombatResultStatus::CHARACTER_VICTORY)throw new InconsistentHuntRewardException('Hunt is not rewardable.');$existing=HuntReward::where('hunt_id',$hunt->id)->lockForUpdate()->first();if($existing)return$this->result($existing->load('items'));$enemies=HuntEnemy::where('hunt_id',$hunt->id)->orderBy('position')->lockForUpdate()->get();$this->validateEnemies($hunt,$enemies);$reward=HuntReward::create(['hunt_id'=>$hunt->id,'hunting_session_id'=>$hunt->hunting_session_id,'status'=>HuntRewardStatus::PENDING,'generated_at'=>now(),'claimed_at'=>null]);$monsterIds=$enemies->pluck('monster_id')->unique()->values();$monsters=Monster::whereIn('id',$monsterIds)->lockForUpdate()->get()->keyBy('id');if($monsters->count()!==$monsterIds->count())throw new InconsistentHuntRewardException('Monster catalog missing.');$entries=MonsterLootEntry::whereIn('monster_id',$monsterIds)->where('status',CatalogStatus::ACTIVE)->whereHas('item',function($q){$q->where('status',CatalogStatus::ACTIVE);})->with('item')->orderBy('sort_order')->orderBy('id')->lockForUpdate()->get()->groupBy('monster_id');foreach($enemies as $enemy){$monster=$monsters->get($enemy->monster_id);$loot=$this->loot->generateFromLoadedEntries($monster,$entries->get($enemy->monster_id,collect()));foreach($loot->drops() as $drop){$quantity=$drop->quantity();if(!is_int($quantity)||$quantity<=0)throw new InvalidArgumentException('Invalid reward quantity.');HuntRewardItem::create(['hunt_reward_id'=>$reward->id,'hunt_enemy_id'=>$enemy->id,'item_id'=>$drop->itemId(),'source_instance_identifier'=>$enemy->instance_identifier,'item_code_snapshot'=>$drop->itemCode(),'item_name_snapshot'=>$drop->itemName(),'quantity'=>$quantity]);}}return$this->result($reward->load('items'));}
 private function validateEnemies(Hunt $hunt,$enemies){if($enemies->count()!==$hunt->enemy_count||$enemies->pluck('position')->all()!==range(1,$hunt->enemy_count)||$enemies->pluck('instance_identifier')->filter()->unique()->count()!==$hunt->enemy_count)throw new InconsistentHuntRewardException('Enemy encounter mismatch.');foreach($enemies as $enemy)if($enemy->status!==HuntEnemyStatus::DEFEATED||(int)$enemy->final_health!==0)throw new InconsistentHuntRewardException('Victory enemy is not defeated.');}private function result(HuntReward $reward){$items=$reward->items->map(function($i){return new HuntRewardItemResult($i->id,$i->hunt_enemy_id,$i->source_instance_identifier,$i->item_id,$i->item_code_snapshot,$i->item_name_snapshot,$i->quantity);})->all();return new HuntRewardResult($reward->id,$reward->hunt_id,$reward->hunting_session_id,$reward->status,$reward->generated_at->toIso8601String(),$items);}
 public function summary($sessionId){$base=HuntReward::where('hunting_session_id',$sessionId)->where('status',HuntRewardStatus::PENDING);$rewards=$base->count();$withItems=(clone$base)->whereHas('items')->count();$totals=DB::table('hunt_reward_items as i')->join('hunt_rewards as r','r.id','=','i.hunt_reward_id')->where('r.hunting_session_id',$sessionId)->where('r.status',HuntRewardStatus::PENDING)->select('i.item_id','i.item_code_snapshot','i.item_name_snapshot',DB::raw('SUM(i.quantity) quantity'))->groupBy('i.item_id','i.item_code_snapshot','i.item_name_snapshot')->orderBy('i.item_name_snapshot')->get();return['rewards_count'=>$rewards,'rewards_with_items_count'=>$withItems,'item_lines_count'=>(int)DB::table('hunt_reward_items as i')->join('hunt_rewards as r','r.id','=','i.hunt_reward_id')->where('r.hunting_session_id',$sessionId)->count(),'total_quantity'=>(int)$totals->sum('quantity'),'items'=>$totals->map(function($x){return['item_id'=>$x->item_id,'item_code'=>$x->item_code_snapshot,'item_name'=>$x->item_name_snapshot,'quantity'=>(int)$x->quantity];})->all()];}}
